// ══════════════════════════════════════════════════════
//  RICK ASTLEY — Web Audio API synth
//  Never Gonna Give You Up — mélodie principale
// ══════════════════════════════════════════════════════
function useRickAstley() {
  const ctxRef = useRef(null);
  const playingRef = useRef(false);
  const timeoutRefs = useRef([]);

  const stopAll = () => {
    timeoutRefs.current.forEach(t => clearTimeout(t));
    timeoutRefs.current = [];
    playingRef.current = false;
  };

  const play = useCallback(() => {
    if (playingRef.current) return;
    playingRef.current = true;

    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    if (!ctxRef.current || ctxRef.current.state === "closed") {
      ctxRef.current = new AudioCtx();
    }
    const ctx = ctxRef.current;
    if (ctx.state === "suspended") ctx.resume();

    // Notes: Never Gonna Give You Up chorus melody (simplified)
    // A4=440, note durations in seconds
    const NOTE = (name) => {
      const notes = {C4:261.63,D4:293.66,E4:329.63,F4:349.23,G4:392,A4:440,B4:493.88,
                     C5:523.25,D5:587.33,E5:659.25,F5:698.46,G5:783.99,A5:880,B5:987.77,
                     C3:130.81,D3:146.83,E3:164.81,G3:196,A3:220,B3:246.94,R:0};
      return notes[name] || 0;
    };

    // "Never gonna give you up" simplified melody
    const BPM = 120;
    const B = 60/BPM; // beat duration

    const melody = [
      // "We're no strangers to love..."
      [NOTE("A4"),B*0.5],[NOTE("A4"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("D5"),B*0.5],
      [NOTE("D5"),B*0.75],[NOTE("B4"),B*0.25],[NOTE("C5"),B],[NOTE("A4"),B],
      // "You know the rules and so do I"
      [NOTE("A4"),B*0.5],[NOTE("G4"),B*0.5],[NOTE("A4"),B*0.5],[NOTE("D4"),B*0.5],
      [NOTE("E4"),B],[NOTE("G4"),B],[NOTE("A4"),B*1.5],[NOTE("R"),B*0.5],
      // "Never gonna give you up"
      [NOTE("A4"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("D5"),B*0.75],[NOTE("B4"),B*0.25],
      [NOTE("E5"),B*1.5],[NOTE("R"),B*0.5],
      [NOTE("A4"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("D5"),B*0.75],[NOTE("B4"),B*0.25],
      [NOTE("D5"),B*1],[NOTE("C5"),B*0.75],[NOTE("B4"),B*0.25],[NOTE("A4"),B*1],
      // "Never gonna let you down"
      [NOTE("A4"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("D5"),B*0.75],[NOTE("B4"),B*0.25],
      [NOTE("C5"),B*1.5],[NOTE("R"),B*0.5],
      [NOTE("A4"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("D5"),B*0.75],[NOTE("B4"),B*0.25],
      [NOTE("C5"),B*0.75],[NOTE("D5"),B*0.25],[NOTE("C5"),B*0.5],[NOTE("B4"),B*0.5],[NOTE("A4"),B*1],
    ];

    const playNote = (freq, startTime, duration) => {
      if (freq === 0) return;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      const dist = ctx.createWaveShaper();

      // slight warmth
      const curve = new Float32Array(256);
      for (let i = 0; i < 256; i++) { const x = (i*2)/256-1; curve[i] = (Math.PI+200)*x/(Math.PI+200*Math.abs(x)); }
      dist.curve = curve;

      osc.type = "square";
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.12, startTime + 0.01);
      gain.gain.setValueAtTime(0.12, startTime + duration - 0.05);
      gain.gain.linearRampToValueAtTime(0, startTime + duration);

      osc.connect(dist); dist.connect(gain); gain.connect(ctx.destination);
      osc.start(startTime);
      osc.stop(startTime + duration);
    };

    let t = ctx.currentTime + 0.1;
    melody.forEach(([freq, dur]) => { playNote(freq, t, dur * 0.9); t += dur; });

    // Loop
    const totalDuration = melody.reduce((acc, [,d]) => acc + d, 0);
    const loopFn = () => {
      if (!playingRef.current) return;
      let lt = ctxRef.current.currentTime + 0.05;
      melody.forEach(([freq, dur]) => { playNote(freq, lt, dur * 0.9); lt += dur; });
      const tid = setTimeout(loopFn, totalDuration * 1000 - 200);
      timeoutRefs.current.push(tid);
    };
    const tid = setTimeout(loopFn, totalDuration * 1000 - 200);
    timeoutRefs.current.push(tid);
  }, []);

  return { play, stop: stopAll };
}

// ══════════════════════════════════════════════════════
//  CONFETTI
// ══════════════════════════════════════════════════════
function Confetti({ active }) {
  const canvasRef = useRef(null);
  const animRef   = useRef(null);
  const pieces    = useRef([]);

  const initPieces = () => Array.from({ length: 200 }, () => ({
    x: Math.random() * window.innerWidth,
    y: Math.random() * window.innerHeight - window.innerHeight,
    w: Math.random() * 14 + 6, h: Math.random() * 7 + 4,
    color: ["#ff6eb4","#c084fc","#fbbf24","#34d399","#60a5fa","#f472b6","#fb923c","#a78bfa","#f9a8d4"][Math.floor(Math.random()*9)],
    rot: Math.random()*360, vx:(Math.random()-0.5)*3, vy:Math.random()*3+1.5, vr:(Math.random()-0.5)*8,
  }));

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    resize();
    window.addEventListener("resize", resize);
    return () => window.removeEventListener("resize", resize);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    if (!active) {
      // Let existing pieces fall off naturally — no reset, no loop
      // Just keep animating until all pieces are below screen
      const fallOff = () => {
        if (!canvas) return;
        const stillVisible = pieces.current.some(p => p.y < canvas.height + 20);
        if (!stillVisible) {
          cancelAnimationFrame(animRef.current);
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          return;
        }
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        pieces.current.forEach(p => {
          ctx.save(); ctx.translate(p.x+p.w/2, p.y+p.h/2); ctx.rotate(p.rot*Math.PI/180);
          ctx.fillStyle = p.color; ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h); ctx.restore();
          p.x += p.vx; p.y += p.vy; p.rot += p.vr;
          // No respawn — just fall off
        });
        animRef.current = requestAnimationFrame(fallOff);
      };
      cancelAnimationFrame(animRef.current);
      animRef.current = requestAnimationFrame(fallOff);
      return;
    }

    // Active : spawn and loop
    pieces.current = initPieces();
    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      pieces.current.forEach(p => {
        ctx.save(); ctx.translate(p.x+p.w/2, p.y+p.h/2); ctx.rotate(p.rot*Math.PI/180);
        ctx.fillStyle = p.color; ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h); ctx.restore();
        p.x += p.vx; p.y += p.vy; p.rot += p.vr;
        if (p.y > canvas.height) { p.y = -20; p.x = Math.random() * canvas.width; }
      });
      animRef.current = requestAnimationFrame(draw);
    };
    cancelAnimationFrame(animRef.current);
    draw();
    return () => cancelAnimationFrame(animRef.current);
  }, [active]);

  return <canvas ref={canvasRef} style={{position:"fixed",top:0,left:0,pointerEvents:"none",zIndex:999}}/>;
}

