// ─── GAME 1 ───────────────────────────────────────────
function Game1({onSuccess, onFail}) {
  const [result, setResult] = useState(null);
  const handleSwipe = (p, right) => {
    if (result) return;
    if (right && p.match)   { setResult("win");  setTimeout(onSuccess, 1400); }
    else if (right && !p.match) { setResult("lose"); }
  };
  return (
    <div style={PAGE}>
      <div style={CARD}>
        <div style={STEP}>Épreuve 1 / 4</div>
        <div style={TITLE}>🔍 Trouvez Lisa sur Hinge !</div>
        <div style={SUB}>💚 swipez à droite sur le bon profil · ✕ pour passer</div>
        {result==="win"  && <div style={{color:"#22c55e",fontWeight:"bold",fontSize:"1.1rem",marginBottom:"10px"}}>✅ C'est bien Lisa ! Bravo ! 💕</div>}
        {result==="lose" && <div style={{marginBottom:"12px"}}>
          <div style={{color:"#ef4444",fontWeight:"bold",marginBottom:"8px"}}>❌ Ce n'est pas Lisa… 😬</div>
          <button style={btn("pink")} onClick={onFail}>Recommencer depuis le début</button>
        </div>}
        {!result && (
          <div style={{display:"flex",flexDirection:"column",gap:"10px"}}>
            {PROFILES.map((p,i) => (
              <div key={i} style={{
                background:"linear-gradient(135deg,#fff0f8,#f5e6ff)", borderRadius:"20px",
                padding:"12px 14px", border:"1.5px solid #f9a8d4",
                display:"flex", alignItems:"center", gap:"12px",
              }}>
                <img src={svgToDataUrl(GIRL_AVATARS[p.avatarIdx])} alt={p.name}
                  style={{width:"60px",height:"60px",borderRadius:"50%",border:"2.5px solid #f9a8d4",flexShrink:0}}/>
                <div style={{flex:1, textAlign:"left"}}>
                  <div style={{fontWeight:"bold",color:"#b03080",fontSize:"0.92rem"}}>{p.name}</div>
                  <div style={{fontSize:"0.78rem",color:"#7c3aed",lineHeight:"1.4"}}>{p.bio}</div>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:"6px"}}>
                  <button style={{...btn("pink"),padding:"8px 13px",fontSize:"0.9rem",margin:0}} onClick={()=>handleSwipe(p,true)}>💚</button>
                  <button style={{...btn("red"), padding:"8px 13px",fontSize:"0.9rem",margin:0}} onClick={()=>handleSwipe(p,false)}>✕</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── GAME 2 ───────────────────────────────────────────
function Game2({onSuccess}) {
  const [sel, setSel]       = useState([]);
  const [feedback, setFeedback] = useState(null);
  const toggle = (i) => { setSel(s=>s.includes(i)?s.filter(x=>x!==i):[...s,i]); setFeedback(null); };
  const check  = () => {
    const goodIdx = PHRASES.map((p,i)=>p.ok?i:-1).filter(i=>i>=0);
    const ok = goodIdx.every(i=>sel.includes(i)) && sel.every(i=>goodIdx.includes(i));
    setFeedback(ok?"win":"lose");
    if(ok) setTimeout(onSuccess,1500);
  };
  return (
    <div style={PAGE}>
      <div style={CARD}>
        <div style={STEP}>Épreuve 2 / 4</div>
        <div style={TITLE}>💬 Choisissez vos phrases d'accroche !</div>
        <div style={SUB}>Sélectionnez TOUTES les phrases qui pourraient séduire Lisa ✨</div>
        <div style={{display:"flex",flexDirection:"column",gap:"8px",marginBottom:"14px"}}>
          {PHRASES.map((p,i)=>(
            <div key={i} onClick={()=>feedback!=="win"&&toggle(i)} style={{
              padding:"11px 14px",borderRadius:"14px",cursor:"pointer",textAlign:"left",
              border:sel.includes(i)?"2px solid #c084fc":"2px solid #f9a8d4",
              background:sel.includes(i)?"linear-gradient(135deg,#fce7f3,#f3e8ff)":"white",
              color:"#7c3aed",fontWeight:sel.includes(i)?"bold":"normal",
              transition:"all 0.2s",fontSize:"0.88rem",
            }}>
              {sel.includes(i)?"✅ ":"○ "}{p.text}
            </div>
          ))}
        </div>
        {feedback==="lose" && (
          <div style={{marginBottom:"8px"}}>
            <div style={{color:"#ef4444",fontWeight:"bold",marginBottom:"8px"}}>❌ Pas tout à fait… Réessaie !</div>
            <button style={btn("gray")} onClick={()=>{ setSel([]); setFeedback(null); }}>🔄 Réessayer</button>
          </div>
        )}
        {feedback==="win"  && <div style={{color:"#22c55e",fontWeight:"bold",marginBottom:"8px"}}>💕 Parfait ! Tu sais comment lui parler !</div>}
        {feedback!=="win"  && <button style={btn("pink")} onClick={check}>Valider 💌</button>}
      </div>
    </div>
  );
}

// ─── GAME 3 ───────────────────────────────────────────
function Game3({onSuccess}) {
  const [chosen,setChosen]=useState(null);
  const pick=(m)=>{ setChosen(m); if(m.correct) setTimeout(onSuccess,1500); };
  return (
    <div style={PAGE}>
      <div style={CARD}>
        <div style={STEP}>Épreuve 3 / 4</div>
        <div style={TITLE}>🏋️ Devine le muscle préféré de Lisa !</div>
        <div style={SUB}>Quel groupe musculaire fait craquer Lisa ? 👀</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px"}}>
          {MUSCLES.map((m,i)=>{
            const picked=chosen===m;
            return (
              <button key={i} onClick={()=>pick(m)} style={{
                padding:"16px 10px",borderRadius:"16px",cursor:"pointer",fontFamily:"'Nunito', sans-serif",
                border:`2px solid ${picked?(m.correct?"#22c55e":"#ef4444"):"#f9a8d4"}`,
                background:picked?(m.correct?"#d1fae5":"#fee2e2"):"linear-gradient(135deg,#fff0f8,#f5e6ff)",
                transition:"transform 0.15s",
              }}>
                <img src={MUSCLE_IMGS[m.img]} alt={m.name}
                  style={{width:"80px",height:"60px",objectFit:"cover",borderRadius:"10px",marginBottom:"4px"}}/>
                <div style={{fontSize:"0.82rem",color:"#7c3aed",fontWeight:"bold",marginTop:"4px"}}>{m.name}</div>
                {picked&&<div style={{fontSize:"0.78rem",marginTop:"4px",color:m.correct?"#16a34a":"#dc2626"}}>{m.correct?"🎉 C'est ça !":"❌ Non !"}</div>}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ── KEY CARD with SVG key shape ──────────────────────────────
function KeyCard({ k, isDragging, wasTried, onPointerDown }) {
  return (
    <div
      onMouseDown={e => onPointerDown(e, k)}
      onTouchStart={e => onPointerDown(e, k)}
      style={{
        display:"flex", flexDirection:"column", alignItems:"center",
        cursor:"grab", userSelect:"none", touchAction:"none",
        opacity: isDragging || wasTried ? 0.35 : 1,
        transition:"opacity 0.2s, transform 0.15s",
        padding:"6px",
      }}>
      {/* SVG clé avec Pokémon au bout */}
      <svg width="70" height="110" viewBox="0 0 70 110" style={{overflow:"visible", filter: k.correct && !isDragging ? "drop-shadow(0 0 6px #f472b6)" : "none"}}>
        {/* Anneau de la clé */}
        <circle cx="35" cy="22" r="16" fill={k.color} stroke="#c084fc" strokeWidth="3"/>
        <circle cx="35" cy="22" r="9" fill="white" stroke="#c084fc" strokeWidth="2"/>
        {/* Tige */}
        <rect x="32" y="36" width="6" height="38" rx="3" fill={k.color} stroke="#c084fc" strokeWidth="2"/>
        {/* Dents de la clé */}
        <rect x="38" y="52" width="9" height="5" rx="2" fill={k.color} stroke="#c084fc" strokeWidth="1.5"/>
        <rect x="38" y="63" width="7" height="5" rx="2" fill={k.color} stroke="#c084fc" strokeWidth="1.5"/>
        {/* Image Pokémon dans l'anneau */}
        <clipPath id={"clip-"+k.key}>
          <circle cx="35" cy="22" r="13"/>
        </clipPath>
        <image
          href={PKM_IMGS[k.key]}
          x="22" y="9" width="26" height="26"
          clipPath={"url(#clip-"+k.key+")"}
          preserveAspectRatio="xMidYMid slice"
        />
      </svg>
      <div style={{fontSize:"0.68rem", color:"#7c3aed", fontWeight:"bold", marginTop:"2px", textAlign:"center", maxWidth:"70px"}}>{k.name}</div>
    </div>
  );
}

// ─── GAME 4 : DRAG & DROP CLÉ POKÉMON ────────────────
function Game4({onSuccess}) {
  const [dragging, setDragging]     = useState(null);
  const [pos, setPos]               = useState({x:0,y:0});
  const [tried, setTried]           = useState(null);
  const [heartBurst, setHeartBurst] = useState(false);
  const heartRef = useRef(null);

  const onPointerDown = (e, key) => {
    if (heartBurst) return;
    e.preventDefault();
    const touch = e.touches ? e.touches[0] : e;
    setPos({x: touch.clientX, y: touch.clientY});
    setDragging(key);
  };

  const onMove = useCallback((e) => {
    if (!dragging) return;
    e.preventDefault();
    const touch = e.touches ? e.touches[0] : e;
    setPos({x: touch.clientX, y: touch.clientY});
  }, [dragging]);

  const onUp = useCallback((e) => {
    if (!dragging) return;
    const touch = e.changedTouches ? e.changedTouches[0] : e;
    if (heartRef.current) {
      const r = heartRef.current.getBoundingClientRect();
      const hx = r.left + r.width/2, hy = r.top + r.height/2;
      if (Math.hypot(touch.clientX - hx, touch.clientY - hy) < 65) {
        setTried(dragging);
        if (dragging.correct) { setHeartBurst(true); setTimeout(onSuccess, 1800); }
        setDragging(null); return;
      }
    }
    setDragging(null);
  }, [dragging, onSuccess]);

  useEffect(() => {
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup",   onUp);
    window.addEventListener("touchmove", onMove, {passive:false});
    window.addEventListener("touchend",  onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup",   onUp);
      window.removeEventListener("touchmove", onMove);
      window.removeEventListener("touchend",  onUp);
    };
  }, [onMove, onUp]);

  return (
    <div style={PAGE}>
      <div style={CARD}>
        <div style={STEP}>Épreuve 4 / 4</div>
        <div style={TITLE}>🔐 Ouvre le cœur de Lisa !</div>
        <div style={SUB}>Glisse la bonne clé Pokémon vers le cœur 💜<br/><span style={{fontSize:"0.8rem",color:"#c084fc"}}>👆 Fais glisser avec ton doigt !</span></div>

        <div ref={heartRef} style={{
          fontSize: heartBurst ? "5rem" : "3.8rem",
          marginBottom:"14px", transition:"all 0.3s",
          animation: heartBurst ? "heartpop 0.5s ease" : "none",
          filter: heartBurst ? "drop-shadow(0 0 18px #f472b6)" : tried&&!tried.correct ? "drop-shadow(0 0 8px #ef4444)" : "none",
        }}>
          {heartBurst ? "💖" : tried&&!tried.correct ? "💔" : "🔒"}
        </div>

        {tried && !tried.correct && !heartBurst &&
          <div style={{color:"#ef4444",fontWeight:"bold",marginBottom:"8px",fontSize:"0.88rem"}}>
            ❌ {tried.name} n'est pas la bonne clé… Réessaie !
          </div>}
        {heartBurst &&
          <div style={{color:"#22c55e",fontWeight:"bold",fontSize:"1.1rem",marginBottom:"8px"}}>
            🌟 C'est Mew ! Le cœur s'ouvre ! 💖
          </div>}

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px",touchAction:"none"}}>
          {KEYS_DATA.map((k,i) => {
            const isDragging = dragging?.key===k.key;
            const wasTried   = tried?.key===k.key && !tried?.correct;
            return (
              <div key={i}
                onMouseDown={e=>onPointerDown(e,k)}
                onTouchStart={e=>onPointerDown(e,k)}
                style={{
                  padding:"10px 6px", borderRadius:"16px", border:"2px solid #f9a8d4",
                  background:k.color, cursor:"grab", userSelect:"none", touchAction:"none",
                  opacity: isDragging||wasTried ? 0.4 : 1, transition:"opacity 0.2s",
                  display:"flex", flexDirection:"column", alignItems:"center", gap:"2px",
                }}>
                <div style={{fontSize:"1rem",color:"#9060a0"}}>🗝️</div>
                <img src={PKM_IMGS[k.key]} alt={k.name}
                  style={{width:"54px",height:"54px",imageRendering:"pixelated"}}
                  draggable="false"/>
                <div style={{fontSize:"0.72rem",color:"#7c3aed",fontWeight:"bold"}}>{k.name}</div>
              </div>
            );
          })}
        </div>

        {dragging && createPortal(
          <div style={{
            position:"fixed",
            left: pos.x,
            top: pos.y,
            zIndex:9999,
            pointerEvents:"none",
            transform:"translate(-50%, -50%) scale(1.15)",
          }}>
            <KeyCard k={dragging} isDragging={false} wasTried={false} onPointerDown={()=>{}}/>
          </div>,
          document.body
        )}
      </div>
      <style>{`@keyframes heartpop{0%{transform:scale(1)}40%{transform:scale(1.6)}70%{transform:scale(0.9)}100%{transform:scale(1.25)}}`}</style>
    </div>
  );
}

// ─── FINAL ────────────────────────────────────────────
function FinalScreen() {
  const audioRef = useRef(null);
  const [musicStarted, setMusicStarted] = useState(false);
  const [confettiActive, setConfettiActive] = useState(true);
  const RICK_MP3 = "data:audio/mp3;base64,";

  const startMusic = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.play().then(() => setMusicStarted(true)).catch(() => {});
    }
  }, []);

  // Auto-start on mount, stop confetti after 3s
  useEffect(() => {
    const t = setTimeout(() => { startMusic(); }, 300);
    const t2 = setTimeout(() => { setConfettiActive(false); }, 3000);
    return () => { clearTimeout(t); clearTimeout(t2); };
  }, [startMusic]);

  const relaunchConfetti = () => {
    setConfettiActive(false);
    setTimeout(() => setConfettiActive(true), 50);
    setTimeout(() => setConfettiActive(false), 3050);
  };

  return (
    <div style={{...PAGE, overflow:"hidden", position:"relative"}}>
      <audio ref={audioRef} src={RICK_MP3} loop/>
      <Confetti active={confettiActive}/>
      <div style={{...CARD, zIndex:10, position:"relative"}}>
        <div style={{fontSize:"3.5rem",marginBottom:"8px",animation:"bounce 0.8s infinite"}}>🎉💕🎊</div>
        <div style={{fontSize:"2rem",fontWeight:"bold",color:"#b03080",marginBottom:"10px",fontFamily:"'Pacifico', cursive"}}>
          FÉLICITATIONS !!!
        </div>
        <div style={{fontSize:"1rem",color:"#7c3aed",marginBottom:"12px",fontWeight:"bold"}}>
          Vous avez séduit Lisa P. 😭❤️
        </div>
        <div style={{
          fontSize:"1.15rem", margin:"12px 0", padding:"16px", borderRadius:"18px",
          background:"linear-gradient(135deg,#fce7f3,#f3e8ff)", border:"2px solid #f9a8d4",
        }}>
          🫂 Vous êtes désormais <strong>EN COUPLE</strong> avec Lisa !<br/>
          <span style={{fontSize:"1.5rem"}}>😭❤️🎊</span>
        </div>

        <div style={{
          background:"linear-gradient(135deg,#f5d0fe,#fce7f3)", borderRadius:"16px",
          padding:"12px", marginBottom:"12px", border:"2px solid #e879f9"
        }}>
          <div style={{fontWeight:"bold",color:"#86198f",marginBottom:"6px",fontSize:"0.95rem"}}>
            🎵 Never Gonna Give You Up — Rick Astley 🎵
          </div>
          {!musicStarted ? (
            <button style={btn("pink")} onClick={startMusic}>▶️ Lancer la musique !</button>
          ) : (
            <div>
              <div style={{color:"#22c55e",fontWeight:"bold",fontSize:"0.88rem",marginBottom:"6px"}}>
                🎶 ♩ ♪ Never Gonna Give You Up ♪ ♩ 🎶
              </div>
              <button style={{...btn("gray"), fontSize:"0.8rem", padding:"7px 16px"}}
                onClick={()=>{ if(audioRef.current){ audioRef.current.pause(); audioRef.current.currentTime=0; setMusicStarted(false); }}}>
                ⏹ Stop
              </button>
            </div>
          )}

        </div>

        <div style={{fontSize:"2rem",marginBottom:"10px"}}>💖🌟💘✨💝🎀</div>
        <button style={{...btn("pink"), fontSize:"0.9rem", padding:"10px 20px"}} onClick={relaunchConfetti}>
          🎊 Encore des confettis !
        </button>
      </div>
      <style>{`@keyframes bounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}`}</style>
    </div>
  );
}

// ══════════════════════════════════════════════════════
//  APP
// ══════════════════════════════════════════════════════
export default function App() {
  const [screen, setScreen] = useState("welcome");
  const go = s => setScreen(s);
  return (
    <>
      <style>{`*{box-sizing:border-box;}body{margin:0;}button:hover{transform:scale(1.04)!important;}button:active{transform:scale(0.97)!important;}`}</style>
      {screen==="welcome" && <WelcomeScreen onYes={()=>go("game1")} onNo={()=>go("no")}/>}
      {screen==="no"      && <NoScreen onBack={()=>go("welcome")}/>}
      {screen==="game1"   && <Game1 onSuccess={()=>go("game2")} onFail={()=>go("welcome")}/>}
      {screen==="game2"   && <Game2 onSuccess={()=>go("game3")}/>}
      {screen==="game3"   && <Game3 onSuccess={()=>go("game4")}/>}
      {screen==="game4"   && <Game4 onSuccess={()=>go("final")}/>}
      {screen==="final"   && <FinalScreen/>}
    </>
  );
}
